const NavItem = ({ view, label, icon: Icon, active, collapsed, currentView, navigateTo }: {
  view?: string; label: string; icon: React.ElementType; active?: boolean; collapsed?: boolean; currentView: string; navigateTo: (view: string) => void;
}) => {
  const handleClick = () => view && navigateTo(view);
  const isActive = active !== undefined ? active : (view && currentView === view);

