import React from 'react';
import { Loader2 } from 'lucide-react';

interface GoldButtonProps {
  children: React.ReactNode;
  onClick?: () => void;
  disabled?: boolean;
  loading?: boolean;
  variant?: 'primary' | 'secondary' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  className?: string;
  type?: 'button' | 'submit';
  icon?: React.ReactNode;
}

const GoldButton: React.FC<GoldButtonProps> = ({
  children,
  onClick,
  disabled = false,
  loading = false,
  variant = 'primary',
  size = 'md',
  className = '',
  type = 'button',
  icon,
}) => {
  const baseClasses = 'relative inline-flex items-center justify-center gap-2 font-bold rounded-full transition-all duration-300 overflow-hidden';

  const sizeClasses = {
    sm: 'px-4 py-2 text-xs',
    md: 'px-6 py-3 text-sm',
    lg: 'px-8 py-4 text-base',
  };

  const variantClasses = {
    primary: 'bg-gradient-to-r from-gold-400 via-gold-500 to-gold-600 text-black hover:brightness-110 hover:-translate-y-0.5 shadow-lg shadow-gold-500/20 disabled:opacity-60 disabled:cursor-not-allowed',
    secondary: 'bg-gold-400/10 border border-gold-400/20 text-gold-300 hover:bg-gold-400/20 hover:border-gold-400/30 disabled:opacity-60',
    ghost: 'text-gold-400 hover:bg-gold-400/10 disabled:opacity-60',
  };

  return (
    <button
      type={type}
      onClick={onClick}
      disabled={disabled || loading}
