import React from 'react';
import { LayoutDashboard, Store, ScanLine, User as UserIcon } from 'lucide-react';
import { useTranslation } from '../i18n';

interface MobileBottomNavProps {
  currentView: string;
  navigateTo: (view: string) => void;
  isMobileMenuOpen: boolean;
}

const MobileBottomNav: React.FC<MobileBottomNavProps> = ({ currentView, navigateTo, isMobileMenuOpen }) => {
  const { t } = useTranslation();

  return (
    <div className={`md:hidden fixed bottom-0 left-0 right-0 bg-black/90 backdrop-blur-lg border-t border-gold-400/[0.06] z-50 pb-safe transition-opacity duration-200 ${isMobileMenuOpen ? 'opacity-0 pointer-events-none' : 'opacity-100'}`}>
      <div className="flex justify-around items-center h-16 px-2 relative">
        {[
          { view: 'dashboard', icon: LayoutDashboard, label: t.nav.dash },
          { view: 'marketplace', icon: Store, label: 'Market' },
          { view: 'analyze', icon: ScanLine, label: t.nav.audit },
          { view: 'account', icon: UserIcon, label: t.nav.account },
        ].map((item) => {
          const isActive = currentView === item.view;
          return (
            <button key={item.view} onClick={() => navigateTo(item.view)} className={`relative flex flex-col items-center justify-center w-full h-full space-y-1 transition-all duration-200 ${isActive ? 'text-gold-400' : 'text-gray-500'}`}>
              {isActive && <div className="absolute top-0 left-1/2 -translate-x-1/2 w-8 h-0.5 rounded-full bg-gradient-to-r from-gold-400 to-gold-500" />}
              <item.icon size={20} className={`transition-transform duration-200 ${isActive ? 'scale-110' : ''}`} />
              <span className={`text-[10px] font-medium ${isActive ? 'font-bold' : ''}`}>{item.label}</span>
            </button>
          );
        })}
      </div>
    </div>
  );
};

export default MobileBottomNav;

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { Sparkles, Zap } from 'lucide-react';

const OnboardingModal: React.FC<{ show: boolean; onClose: () => void; onNavigate: (view: string) => void }> = ({ show, onClose, onNavigate }) => {
  const [step, setStep] = useState(0);

  useEffect(() => {
    if (show) document.body.style.overflow = 'hidden';
    return () => { document.body.style.overflow = ''; };
  }, [show]);

  if (!show) return null;

  const handleSkip = () => { localStorage.setItem('citedby_public_onboarded', 'true'); onClose(); };

  const modalContent = (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
      <div className="relative w-full max-w-[480px] bg-surface-100 border border-gold-400/[0.1] rounded-2xl shadow-2xl overflow-hidden max-h-[90vh] overflow-y-auto">
        <button onClick={handleSkip} className="absolute top-4 right-4 text-gray-500 hover:text-gray-300 text-sm z-10">Passer</button>
        {step === 0 && (
          <div className="px-8 pt-10 pb-8 flex flex-col items-center text-center animate-in fade-in duration-300">
            <div className="w-20 h-20 rounded-full bg-gradient-to-br from-gold-400 to-gold-600 flex items-center justify-center mb-6 shadow-lg shadow-gold-500/30">
              <Sparkles size={36} className="text-black" />
            </div>
            <h2 className="text-2xl font-bold text-white mb-3">Bienvenue sur CitedBy.ai !</h2>
            <p className="text-gray-400 text-[15px] leading-relaxed mb-8">Vous disposez de <span className="text-gold-400 font-semibold">50 credits offerts</span> pour decouvrir la plateforme d'optimisation AEO.</p>
            <button onClick={() => setStep(1)} className="w-full py-3 bg-gradient-to-r from-gold-400 to-gold-600 text-black font-semibold rounded-xl transition-all shadow-lg shadow-gold-500/20 hover:brightness-110">Decouvrir</button>
          </div>
        )}
        {step === 1 && (
          <div className="px-8 pt-10 pb-8 flex flex-col items-center text-center animate-in fade-in duration-300">
            <h2 className="text-2xl font-bold text-white mb-2">Vos outils cles</h2>
            <p className="text-gray-500 text-sm mb-6">Tout pour optimiser votre visibilite IA</p>
            <div className="w-full flex flex-col gap-3 mb-8">
              {[
                { emoji: '\uD83D\uDD0D', title: 'Audit AEO Instantane', desc: 'Analysez votre visibilite sur ChatGPT, Claude et Gemini' },
                { emoji: '\uD83D\uDCCA', title: 'Monitoring IA', desc: 'Suivez vos citations sur 5 moteurs IA en temps reel' },
                { emoji: '\uD83C\uDFEA', title: 'Marketplace Agences', desc: 'Trouvez des experts AEO certifies pour vous accompagner' },
              ].map((f, i) => (
                <div key={i} className="flex items-start gap-4 p-4 rounded-xl bg-white/[0.03] border border-gold-400/[0.06] text-left">
                  <span className="text-2xl mt-0.5">{f.emoji}</span>
                  <div><h3 className="text-white font-semibold text-[15px] mb-1">{f.title}</h3><p className="text-gray-500 text-[13px] leading-relaxed">{f.desc}</p></div>
                </div>
              ))}
            </div>
            <button onClick={() => setStep(2)} className="w-full py-3 bg-gradient-to-r from-gold-400 to-gold-600 text-black font-semibold rounded-xl transition-all shadow-lg shadow-gold-500/20 hover:brightness-110">Continuer</button>
          </div>
        )}
        {step === 2 && (
          <div className="px-8 pt-10 pb-8 flex flex-col items-center text-center animate-in fade-in duration-300">
            <div className="w-20 h-20 rounded-full bg-gold-400/20 border border-gold-400/30 flex items-center justify-center mb-6">
              <Zap size={36} className="text-gold-400" />
            </div>
            <h2 className="text-2xl font-bold text-white mb-3">Pret a commencer ?</h2>
            <p className="text-gray-400 text-[15px] leading-relaxed mb-8">Lancez votre premier audit ou explorez le dashboard.</p>
            <button onClick={() => { localStorage.setItem('citedby_public_onboarded', 'true'); onClose(); onNavigate('analyze'); }} className="w-full py-3 bg-gradient-to-r from-gold-400 to-gold-600 text-black font-semibold rounded-xl transition-all shadow-lg shadow-gold-500/20 hover:brightness-110 mb-3">Lancer mon premier audit</button>
            <button onClick={() => { localStorage.setItem('citedby_public_onboarded', 'true'); onClose(); onNavigate('dashboard'); }} className="w-full py-3 bg-white/[0.05] hover:bg-white/[0.08] text-gray-300 hover:text-white font-medium rounded-xl transition-all border border-gold-400/[0.08]">Explorer le dashboard</button>
          </div>
        )}
        <div className="flex items-center justify-center gap-2 pb-6">
          {[0, 1, 2].map((s) => (<div key={s} className={`h-2 rounded-full transition-all duration-300 ${step === s ? 'bg-gold-400 w-6' : 'bg-white/[0.15] w-2'}`} />))}
        </div>
      </div>
    </div>
  );

  return createPortal(modalContent, document.body);
};

export default OnboardingModal;

import React, { useState, useRef, useEffect } from 'react';
import { Search } from 'lucide-react';

const CommandPalettePanel: React.FC<{ onClose: () => void; onNavigate: (view: string) => void }> = ({ onClose, onNavigate }) => {
  const [query, setQuery] = useState('');
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => { setTimeout(() => inputRef.current?.focus(), 100); }, []);

  const commands = [
    { id: 'analyze', label: 'Nouvel Audit AEO', icon: '\uD83D\uDD0D', category: 'Navigation' },
    { id: 'dashboard', label: 'Dashboard', icon: '\uD83D\uDCCA', category: 'Navigation' },
    { id: 'monitoring', label: 'Monitoring AEO', icon: '\uD83D\uDCE1', category: 'Navigation' },
    { id: 'marketplace', label: 'Marketplace Agences', icon: '\uD83C\uDFEA', category: 'Navigation' },
    { id: 'recharge', label: 'GTO Gas Station', icon: '\u26FD', category: 'Navigation' },
    { id: 'affiliation', label: 'Affiliation', icon: '\uD83E\uDD1D', category: 'Navigation' },
    { id: 'alerts', label: 'Alertes AEO', icon: '\uD83D\uDD14', category: 'Navigation' },
    { id: 'account', label: 'Compte & Plan', icon: '\uD83D\uDC64', category: 'Navigation' },
  ];

  const filtered = query ? commands.filter(c => c.label.toLowerCase().includes(query.toLowerCase())) : commands;

  return (
    <div className="relative w-full max-w-[560px] bg-surface-100 border border-gold-400/[0.1] rounded-2xl shadow-2xl shadow-black/50 overflow-hidden" onClick={e => e.stopPropagation()}>
      <div className="flex items-center gap-3 px-5 py-4 border-b border-gold-400/[0.08]">
        <Search size={18} className="text-gray-500 shrink-0" />
        <input ref={inputRef} type="text" value={query} onChange={e => setQuery(e.target.value)} placeholder="Rechercher une page..." className="flex-1 bg-transparent text-white text-[15px] placeholder-gray-600 outline-none" />
        <kbd className="hidden sm:flex items-center gap-1 px-2 py-0.5 text-[10px] text-gray-600 bg-white/[0.04] border border-white/[0.08] rounded-md font-mono">ESC</kbd>
      </div>
      <div className="max-h-[340px] overflow-y-auto py-2">
        {filtered.length === 0 ? (
          <div className="px-5 py-8 text-center text-gray-600 text-sm">Aucun resultat</div>
        ) : (
          filtered.map(cmd => (
            <button key={cmd.id} onClick={() => onNavigate(cmd.id)} className="w-full flex items-center gap-3 px-5 py-2.5 text-left hover:bg-gold-400/[0.05] transition-colors group">
              <span className="text-base">{cmd.icon}</span>
              <span className="text-[14px] text-gray-300 group-hover:text-white transition-colors">{cmd.label}</span>
            </button>
          ))
        )}
      </div>
      <div className="px-5 py-3 border-t border-gold-400/[0.06] text-[11px] text-gray-600 text-center">CitedBy.ai Public</div>
    </div>
  );
};

export default CommandPalettePanel;

import React, { useEffect } from 'react';
import { createPortal } from 'react-dom';
import { X } from 'lucide-react';

const ShortcutsModal: React.FC<{ isOpen: boolean; onClose: () => void }> = ({ isOpen, onClose }) => {
  useEffect(() => {
    if (isOpen) document.body.style.overflow = 'hidden';
    return () => { document.body.style.overflow = ''; };
  }, [isOpen]);

  if (!isOpen) return null;

  const modalContent = (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4" onClick={onClose}>
      <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" />
      <div className="relative w-full max-w-[400px] max-h-[90vh] overflow-y-auto bg-surface-100 border border-gold-400/[0.1] rounded-2xl shadow-2xl" onClick={e => e.stopPropagation()}>
        <div className="flex items-center justify-between px-5 py-4 border-b border-gold-400/[0.08]">
          <h3 className="text-sm font-semibold text-white">Raccourcis clavier</h3>
          <button onClick={onClose} className="text-gray-500 hover:text-white transition-colors"><X size={14} /></button>
        </div>
        <div className="px-5 py-3 space-y-2.5">
          {[
            { keys: 'Ctrl + K', desc: 'Recherche rapide' },
            { keys: '?', desc: 'Afficher les raccourcis' },
            { keys: 'Esc', desc: 'Fermer les modales' },
          ].map(s => (
            <div key={s.keys} className="flex items-center justify-between py-1.5">
              <span className="text-sm text-gray-400">{s.desc}</span>
              <kbd className="px-2 py-1 text-[11px] text-gray-500 bg-white/[0.04] border border-white/[0.08] rounded-md font-mono">{s.keys}</kbd>
            </div>
          ))}
        </div>
      </div>
    </div>
  );

  return createPortal(modalContent, document.body);
};

export default ShortcutsModal;
